import React from 'react';

function About() {
  return (
    <section id="about" style={{ height: '100vh', padding: '50px', backgroundColor: '#e4e4e4' }}>
      <h1 style={{ textAlign: 'center', marginTop: 0 }}>About Me</h1>
      <p>This is the about section of my portfolio where I talk about my background.</p>
    </section>
  );
}

export default About;
